#!/usr/bin/env bash
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]:-$0}")" && pwd)"
REPO=""
for d in "$SCRIPT_DIR" ~/Desktop/freddy-fixit ~/freddy-fixit ~/Desktop/Website/freddy-fixit; do
  if [ -d "$d/.git" ]; then REPO="$d"; break; fi
done
[ -n "$REPO" ] || { echo "❌ Could not find the freddy-fixit git repo. Run this script from inside the repo folder."; exit 1; }
cd "$REPO"
echo "Repo: $REPO"
echo "Applying Freddy Fix It batch-2 update (reviews, realtime, emails, saved addresses/vehicles, get-a-quote, SEO, admin health)…"
mkdir -p "$(dirname 'index.html')"
echo '' | base64 -d > 'index.html'
mkdir -p "$(dirname 'src/App.tsx')"
echo '' | base64 -d > 'src/App.tsx'
mkdir -p "$(dirname 'src/components/Ic.tsx')"
echo '' | base64 -d > 'src/components/Ic.tsx'
mkdir -p "$(dirname 'src/components/NewRequest.tsx')"
echo '' | base64 -d > 'src/components/NewRequest.tsx'
mkdir -p "$(dirname 'src/components/TopNav.tsx')"
echo '' | base64 -d > 'src/components/TopNav.tsx'
mkdir -p "$(dirname 'src/components/NotificationBell.tsx')"
echo '' | base64 -d > 'src/components/NotificationBell.tsx'
mkdir -p "$(dirname 'src/pages/AdminDashboard.tsx')"
echo '' | base64 -d > 'src/pages/AdminDashboard.tsx'
mkdir -p "$(dirname 'src/pages/BlogPost.tsx')"
echo '' | base64 -d > 'src/pages/BlogPost.tsx'
mkdir -p "$(dirname 'src/pages/ClientDashboard.tsx')"
echo '' | base64 -d > 'src/pages/ClientDashboard.tsx'
mkdir -p "$(dirname 'src/pages/ContractorDashboard.tsx')"
echo '' | base64 -d > 'src/pages/ContractorDashboard.tsx'
mkdir -p "$(dirname 'src/pages/ContractorProfile.tsx')"
echo '' | base64 -d > 'src/pages/ContractorProfile.tsx'
mkdir -p "$(dirname 'src/pages/Home.tsx')"
echo '' | base64 -d > 'src/pages/Home.tsx'
mkdir -p "$(dirname 'src/pages/GetQuote.tsx')"
echo '' | base64 -d > 'src/pages/GetQuote.tsx'
mkdir -p "$(dirname 'public/robots.txt')"
echo 'VXNlci1hZ2VudDogKgpBbGxvdzogLwpEaXNhbGxvdzogL2FkbWluLWRhc2hib2FyZApEaXNhbGxvdzogL2NsaWVudC1kYXNoYm9hcmQKRGlzYWxsb3c6IC9jb250cmFjdG9yLWRhc2hib2FyZApEaXNhbGxvdzogL3VwZGF0ZS1wYXNzd29yZApEaXNhbGxvdzogL2F1dGgvCgpTaXRlbWFwOiBodHRwczovL2ZyZWRkeWZpeGl0LmNhL3NpdGVtYXAueG1sCg==' | base64 -d > 'public/robots.txt'
mkdir -p "$(dirname 'public/sitemap.xml')"
echo '' | base64 -d > 'public/sitemap.xml'
mkdir -p "$(dirname 'supabase/functions/notify-email/index.ts')"
echo '' | base64 -d > 'supabase/functions/notify-email/index.ts'
git add -A
git commit -m "Batch 2: public reviews, realtime, lifecycle emails, saved addresses/vehicles, get-a-quote lead capture, SEO meta/sitemap, admin health dashboard" || echo "(nothing to commit)"
git push && echo "✅ pushed — hard-refresh the site (Cmd+Shift+R) in ~1–2 min after Vercel builds."
